// ============================================================================
// sRGB cross-validation
// ============================================================================

#[test]
fn srgb_linearize_vs_ultrahdr() {
    let tf = TransferFunction::Srgb;
    for &(input, expected) in ULTRAHDR_SRGB_EOTF {
        let actual = tf.linearize(input, 1.0);
        let diff = (actual - expected).abs();
        assert!(
            diff < 0.005,
            "sRGB linearize({input}): gainforge={actual:.8}, ultrahdr={expected:.8}, diff={diff:.6}"
        );
    }
}

#[test]
fn srgb_gamma_vs_ultrahdr() {
    let tf = TransferFunction::Srgb;
    for &(input, expected) in ULTRAHDR_SRGB_OETF {
        let actual = tf.gamma(input);
        let diff = (actual - expected).abs();
        assert!(
            diff < 0.005,
            "sRGB gamma({input}): gainforge={actual:.8}, ultrahdr={expected:.8}, diff={diff:.6}"
        );
    }
}

// ============================================================================
// PQ cross-validation
//
// gainforge uses pxfm fast-math for PQ; ultrahdr-core uses linear-srgb
// rational polynomials. We expect larger divergence here.
// ============================================================================

#[test]
fn pq_linearize_shape_vs_ultrahdr() {
    let tf = TransferFunction::PerceptualQuantizer;
    // PQ EOTF values from ultrahdr-core. gainforge's PQ may have different
    // reference_display scaling, so we check relative shape rather than exact values.
    //
    // Key property: PQ is extremely nonlinear. 0.5 encoded = 0.0092 linear.
    // At 0.75 encoded = 0.098 linear. At 0.9 = 0.39 linear.
    let pq_half = tf.linearize(0.5, 1.0);
    let pq_075 = tf.linearize(0.75, 1.0);
    let pq_09 = tf.linearize(0.9, 1.0);

    // Shape checks: the ratio between these should be similar regardless of scaling
    // ultrahdr: 0.098/0.0092 ≈ 10.7x, 0.39/0.098 ≈ 3.97x
    if pq_half > 0.0 {
        let ratio_075_05 = pq_075 / pq_half;
        assert!(
            ratio_075_05 > 5.0 && ratio_075_05 < 20.0,
            "PQ shape: 0.75/0.5 ratio = {ratio_075_05:.1}, expected ~10.7"
        );
        let ratio_09_075 = pq_09 / pq_075;
        assert!(
            ratio_09_075 > 2.0 && ratio_09_075 < 8.0,
            "PQ shape: 0.9/0.75 ratio = {ratio_09_075:.1}, expected ~3.97"
        );
    }
}

#[test]
fn pq_endpoints_vs_ultrahdr() {
    let tf = TransferFunction::PerceptualQuantizer;
    // PQ EOTF(0) = 0
    let pq_zero = tf.linearize(0.0, 1.0);
    assert!(pq_zero.abs() < 0.001, "PQ linearize(0) should be ~0: {pq_zero}");

    // PQ EOTF(1.0) ≈ 1.0 (10000/10000 nits)
    // ultrahdr: 0.9999963641
    let pq_one = tf.linearize(1.0, 1.0);
    // Allow wide tolerance due to possible reference_display scaling
    assert!(pq_one > 0.5, "PQ linearize(1.0) should be high: {pq_one}");
}

// ============================================================================
// HLG cross-validation
// ============================================================================

#[test]
fn hlg_oetf_knee_point() {
    // HLG OETF has a knee at 1/12 (≈0.0833): below is sqrt, above is log.
    // ultrahdr: hlg_oetf(1/12) = 0.5 exactly.
    // gainforge uses linearize/gamma which are EOTF/OETF inverses.
    // Test that gamma(linearize(x)) roundtrips for HLG at key points.
    let tf = TransferFunction::HybridLogGamma;

    // At least verify monotonicity across the knee
    let below = tf.gamma(0.05);
    let at_knee = tf.gamma(1.0 / 12.0);
    let above = tf.gamma(0.15);

    assert!(
        below < at_knee && at_knee < above,
        "HLG gamma should be monotonic across knee: {below} < {at_knee} < {above}"
    );
}

