/// GainMapLut from ultrahdr-core: min_boost=1, max_boost=4, gamma=1, weight=0.5
/// byte → gain factor (channel 0)
const ULTRAHDR_GAIN_LUT_W05: &[(u8, f32)] = &[
    (0, 1.00000000),
    (1, 1.00272191),
    (16, 1.04445124),
    (32, 1.09087837),
    (64, 1.19001555),
    (128, 1.41613698),
    (192, 1.68522489),
    (224, 1.83837545),
    (255, 2.00000000),
];

/// GainMapLut from ultrahdr-core: same metadata, weight=1.0 (full boost)
const ULTRAHDR_GAIN_LUT_W10: &[(u8, f32)] = &[
    (0, 1.00000000),
    (1, 1.00545120),
    (16, 1.09087837),
    (32, 1.19001555),
    (64, 1.41613698),
    (128, 2.00544405),
    (192, 2.83998299),
    (224, 3.37962413),
    (255, 4.00000000),
];

#[cfg(feature = "uhdr")]
mod gain_lut_xref {
    use super::*;
    use gainforge::{GainLUT, GainMap, make_gainmap_weight};

    fn test_metadata() -> GainMap {
        GainMap {
            max_content_boost: [4.0; 3],
            min_content_boost: [1.0; 3],
            gamma: [1.0; 3],
            offset_sdr: [0.0; 3],
            offset_hdr: [0.0; 3],
            hdr_capacity_min: 1.0,
            hdr_capacity_max: 16.0,
            use_base_cg: false,
        }
    }

    /// Compare gainforge GainLUT against ultrahdr-core GainMapLut at weight=0.5
    #[test]
    fn gain_lut_w05_vs_ultrahdr() {
        let meta = test_metadata();
        // ultrahdr-core uses 256-entry LUT indexed by byte value.
        // gainforge uses N-entry LUT indexed by float [0,1].
        // Map byte → float: byte/255.0
        let lut = GainLUT::<4096>::new(meta, 0.5);

        for &(byte, expected) in ULTRAHDR_GAIN_LUT_W05 {
            let gain = byte as f32 / 255.0;
            let actual = lut.get_gain_r_factor(gain);
            let rel_err = if expected > 0.01 {
                (actual - expected).abs() / expected
            } else {
                (actual - expected).abs()
            };
            assert!(
                rel_err < 0.03,
                "GainLUT w=0.5 byte={byte} (gain={gain:.4}): \
                 gainforge={actual:.6}, ultrahdr={expected:.6}, rel_err={rel_err:.4}"
            );
        }
    }

    /// Compare at weight=1.0 (full HDR boost)
    #[test]
    fn gain_lut_w10_vs_ultrahdr() {
        let meta = test_metadata();
        let lut = GainLUT::<4096>::new(meta, 1.0);

        for &(byte, expected) in ULTRAHDR_GAIN_LUT_W10 {
            let gain = byte as f32 / 255.0;
            let actual = lut.get_gain_r_factor(gain);
            let rel_err = if expected > 0.01 {
                (actual - expected).abs() / expected
            } else {
                (actual - expected).abs()
            };
            assert!(
                rel_err < 0.03,
                "GainLUT w=1.0 byte={byte} (gain={gain:.4}): \
                 gainforge={actual:.6}, ultrahdr={expected:.6}, rel_err={rel_err:.4}"
            );
        }
    }

    /// Verify endpoints match exactly: gain=0→min_boost, gain=1→max_boost^weight
    #[test]
    fn gain_lut_endpoints_vs_ultrahdr() {
        let meta = test_metadata();

        // weight=0.5: gain=0→1.0, gain=1→4^0.5=2.0
        let lut = GainLUT::<4096>::new(meta, 0.5);
        let at_zero = lut.get_gain_r_factor(0.0);
        let at_one = lut.get_gain_r_factor(1.0);
        assert!(
            (at_zero - 1.0).abs() < 0.01,
            "w=0.5 gain=0: {at_zero}, expected 1.0"
        );
        assert!(
            (at_one - 2.0).abs() < 0.01,
            "w=0.5 gain=1: {at_one}, expected 2.0"
        );

        // weight=1.0: gain=0→1.0, gain=1→4.0
        let lut = GainLUT::<4096>::new(meta, 1.0);
        let at_zero = lut.get_gain_r_factor(0.0);
        let at_one = lut.get_gain_r_factor(1.0);
        assert!(
            (at_zero - 1.0).abs() < 0.01,
            "w=1.0 gain=0: {at_zero}, expected 1.0"
        );
        assert!(
            (at_one - 4.0).abs() < 0.01,
            "w=1.0 gain=1: {at_one}, expected 4.0"
        );
    }
}

