#[test]
fn tonemap_curves_documented() {
    // These aren't testable through gainforge's u8 pipeline, but we document
    // the expected values here so any future f32 API can be validated.
    //
    // Key observations from the ultrahdr-core reference:
    //
    // 1. ACES filmic at x=1.0 maps to 0.804 (not 1.0 — it's a compressive curve)
    // 2. Extended Reinhard at L_max=10 maps x=10→1.0 (exactly at L_max)
    // 3. BT.2390 source=10 target=1 maps x=1.0→0.1 (output scaled by target/source)
    //
    // If gainforge adds a raw f32 tone mapping API, test against these values.

    // Verify the golden data is internally consistent
    for &(x, y) in ULTRAHDR_FILMIC {
        assert!(!y.is_nan(), "ACES filmic NaN at {x}");
        assert!(y >= 0.0 && y <= 1.0, "ACES filmic out of range at {x}: {y}");
    }
    for &(x, y) in ULTRAHDR_REINHARD_LMAX10 {
        assert!(!y.is_nan(), "Reinhard NaN at {x}");
    }
    for &(x, y) in ULTRAHDR_BT2390_SP10_TP1 {
        assert!(!y.is_nan(), "BT.2390 NaN at {x}");
        // Output is scaled by target/source = 0.1
        assert!(y <= 0.11, "BT.2390 sp10 should be ≤0.1: {y} at {x}");
    }
}
